<span class="line"><span style="color:#CDD6F4;">    chunk</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> err </span><span style="color:#94E2D5;">:=</span><span style="color:#CDD6F4;"> stream</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">Recv</span><span style="color:#9399B2;">()</span></span>
