<span class="line"><span style="color:#CDD6F4;">    tok</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> err </span><span style="color:#94E2D5;">:=</span><span style="color:#CDD6F4;"> dec</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">Token</span><span style="color:#9399B2;">()</span></span>
